    40→/* ── Time formatting ────────────────────────────────────────────── */
    41→function elapsed(d: string) {
    42→  const s = Math.floor((Date.now() - new Date(d).getTime()) / 1000);
    43→  if (s < 60)  return `${s}ث`;
    44→  if (s < 3600) return `${Math.floor(s / 60)}د`;
    45→  return `${Math.floor(s / 3600)}س ${Math.floor((s % 3600) / 60)}د`;
    46→}
    47→function isOld(d: string, mins = 15) {
    48→  return (Date.now() - new Date(d).getTime()) > mins * 60_000;
    49→}
    50→function isVeryOld(d: string, mins = 30) {
    51→  return (Date.now() - new Date(d).getTime()) > mins * 60_000;
    52→}
