   128→/* ── Audio beep ─────────────────────────────────────────────────── */
   129→function beep(freq = 880, dur = 0.4) {
   130→  try {
   131→    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
   132→    const osc = ctx.createOscillator();
   133→    const gain = ctx.createGain();
   134→    osc.connect(gain); gain.connect(ctx.destination);
   135→    osc.frequency.value = freq;
   136→    gain.gain.setValueAtTime(0.25, ctx.currentTime);
   137→    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + dur);
   138→    osc.start(); osc.stop(ctx.currentTime + dur);
   139→  } catch {}
   140→}
