   373→/**
   374→ * Center a text string for ESC/POS printers.
   375→ * For Arabic/multilingual text the printer's ESC a 1 center command may miscalculate
   376→ * because UTF-8 bytes ≠ display columns. We pad manually instead.
   377→ * Arabic characters: 2 UTF-8 bytes each but 1 display column → divide byte length by 2.
   378→ */
   379→function centerLine(text: string, width: number = 48): number[] {
   380→  const encoder = new TextEncoder();
   381→  const encoded = encoder.encode(text);
   382→  // Estimate display width: ASCII = 1 col, non-ASCII (Arabic) ≈ 1 col per 2 bytes
   383→  let displayWidth = 0;
   384→  for (let i = 0; i < encoded.length; ) {
   385→    const b = encoded[i];
   386→    if (b < 0x80) { displayWidth += 1; i += 1; }       // ASCII
   387→    else if (b < 0xe0) { displayWidth += 1; i += 2; }  // 2-byte UTF-8 (Arabic, Latin ext)
   388→    else if (b < 0xf0) { displayWidth += 1; i += 3; }  // 3-byte UTF-8
   389→    else               { displayWidth += 1; i += 4; }  // 4-byte UTF-8
   390→  }
   391→  const pad = Math.max(0, Math.floor((width - displayWidth) / 2));
   392→  // Use printer center-align command — more reliable on most printers
   393→  return [...CMD.ALIGN_CENTER, ...textBytes(text), 0x0a];
   394→}
   395→
   396→function dottedLine(width: number = 48): number[] {
   397→  return [...CMD.ALIGN_LEFT, ...textBytes('='.repeat(width)), 0x0a];
   398→}
