   404→function padRow(label: string, value: string, width: number = 48): number[] {
   405→  // label is Arabic (RTL), value is LTR numbers — space between them
   406→  const labelBytes = new TextEncoder().encode(label).length;
   407→  const valueBytes = new TextEncoder().encode(value).length;
   408→  // Estimate display widths (Arabic chars: 2 bytes = 1 col)
   409→  const labelCols = Math.ceil(labelBytes / 2);
   410→  const valueCols = value.length; // numbers/ASCII = 1 col each
   411→  const space = Math.max(1, width - labelCols - valueCols);
   412→  const row = label + ' '.repeat(space) + value;
   413→  return [...CMD.ALIGN_LEFT, ...textBytes(row), 0x0a];
   414→}
