   392→  const fmtT = (iso?: string) => iso ? new Date(iso).toLocaleTimeString('ar-SA', { hour: '2-digit', minute: '2-digit' }) : '';
   393→  const fmtD = (iso?: string) => iso ? new Date(iso).toLocaleDateString('ar-SA', { year: 'numeric', month: 'short', day: 'numeric' }) : '';
   394→
   395→  const startIso = p.openedAt || p.windowStart;
