   397→  const totalCash = p.totalCash ?? p.totalCashSales ?? (p.paymentBreakdown?.cash ?? 0);
   398→  const totalCard = p.totalCard ?? p.totalCardSales ?? ((p.paymentBreakdown?.card ?? 0) + (p.paymentBreakdown?.network ?? 0));
   399→  const totalLoyalty = p.paymentBreakdown?.loyalty ?? 0;
   400→
   401→  const opts = {
