   573→/**
   574→ * Convert a QR/image data URL to ESC/POS GS v 0 raster bytes.
   575→ * Draws the image centered on paper, returns ESC/POS bytes (no init, no cut).
   576→ */
   577→export async function dataUrlToEscPosRaster(
   578→  dataUrl: string,
   579→  paperWidth: '58mm' | '80mm',
   580→  targetPx: number = 200,
   581→): Promise<Uint8Array> {
   582→  const dotWidth = paperWidth === '58mm' ? 384 : 576;
   583→  const img = new Image();
   584→  img.src = dataUrl;
   585→  await new Promise<void>(res => {
   586→    if (img.complete && img.naturalWidth > 0) { res(); return; }
   587→    img.onload = () => res();
   588→    img.onerror = () => res();
   589→    setTimeout(res, 3000);
   590→  });
   591→
   592→  const size = Math.min(targetPx, dotWidth);
   593→  const canvas = document.createElement('canvas');
   594→  canvas.width = dotWidth;
   595→  canvas.height = size + 10;
   596→  const ctx = canvas.getContext('2d')!;
   597→  ctx.fillStyle = '#fff';
   598→  ctx.fillRect(0, 0, canvas.width, canvas.height);
   599→  const x = Math.floor((dotWidth - size) / 2);
   600→  ctx.drawImage(img, x, 5, size, size);
   601→
   602→  const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
   603→  const w = canvas.width;
   604→  const h = canvas.height;
   605→  const bpl = Math.ceil(w / 8);
   606→  const buf: number[] = [];
   607→
   608→  buf.push(0x1d, 0x76, 0x30, 0x00);
   609→  buf.push(bpl & 0xff, (bpl >> 8) & 0xff);
   610→  buf.push(h & 0xff, (h >> 8) & 0xff);
   611→
   612→  for (let y = 0; y < h; y++) {
   613→    for (let bx = 0; bx < bpl; bx++) {
   614→      let byte = 0;
   615→      for (let bit = 0; bit < 8; bit++) {
   616→        const px = bx * 8 + bit;
   617→        if (px < w) {
   618→          const i = (y * w + px) * 4;
   619→          const lum = 0.299 * imgData.data[i] + 0.587 * imgData.data[i + 1] + 0.114 * imgData.data[i + 2];
   620→          if (lum < 128) byte |= 1 << (7 - bit);
   621→        }
   622→      }
   623→      buf.push(byte);
   624→    }
   625→  }
   626→  return new Uint8Array(buf);
   627→}
