   683→    opts.logoDataUrl ? loadImg(opts.logoDataUrl) : Promise.resolve(null),
   684→    opts.trackingQrDataUrl ? loadImg(opts.trackingQrDataUrl) : Promise.resolve(null),
   685→    opts.zatcaQrDataUrl ? loadImg(opts.zatcaQrDataUrl) : Promise.resolve(null),
   686→  ]);
   687→
   688→  // ── Build drawing queue (y-position auto-managed) ────────────────────────
   689→  type DrawOp =
   690→    | { type: 'img'; img: HTMLImageElement; size: number; }
   691→    | { type: 'text'; text: string; align: 'center' | 'left' | 'right'; fs: number; bold: boolean; color?: string; }
   692→    | { type: 'row'; label: string; value: string; fs: number; boldLabel?: boolean; boldValue?: boolean; color?: string; }
   693→    | { type: 'line'; thick?: boolean; dashed?: boolean; }
   694→    | { type: 'gap'; h: number; };
   695→
   696→  const ops: DrawOp[] = [];
   697→
   698→  const addGap   = (h = 6) => ops.push({ type: 'gap', h });
   699→  // Separator line: 2 blank lines above + line + 2 blank lines below
   700→  const LINE_GAP = Math.round(FS * 1.45 * 2);   // ≈ 2 text-line heights
   701→  const addLine  = (thick = false, dashed = false) => {
   702→    ops.push({ type: 'gap', h: LINE_GAP });
   703→    ops.push({ type: 'line', thick, dashed });
   704→    ops.push({ type: 'gap', h: LINE_GAP });
   705→  };
   706→  const addText  = (text: string, align: 'center'|'left'|'right' = 'center', fs = FS, bold = false, color?: string) =>
   707→    ops.push({ type: 'text', text, align, fs, bold, color });
   708→  const addRow   = (label: string, value: string, fs = FS, boldLabel = false, boldValue = false, color?: string) =>
   709→    ops.push({ type: 'row', label, value, fs, boldLabel, boldValue, color });
   710→  const addImg   = (img: HTMLImageElement | null, size: number) => {
   711→    if (img && img.naturalWidth > 0) ops.push({ type: 'img', img, size });
   712→  };
   713→
   714→  // ── RECEIPT LAYOUT — 2 blank lines at the top of every invoice ────────────
   715→  addGap(Math.round(FS * 3.2));
   716→
   717→  // Logo — enlarged, centred. Logo image already contains the shop name.
   718→  addImg(logoImg, Math.round(DW * 0.55));
   719→  addGap(8);
   720→
   721→  // Branch / tagline / VAT — no repeated shop name (it's in the logo)
   722→  if (opts.branchName) addText(opts.branchName, 'center', Math.round(FS * 0.88));
   723→  if (opts.tagline)    addText(opts.tagline, 'center', Math.round(FS * 0.82), false, '#444');
   724→  addText(`VAT: ${opts.vatNumber}`, 'center', Math.round(FS * 0.78), false, '#555');
   725→
   726→  // ── ONE separator line after brand header ───────────────────────────────
   727→  addLine(true);
   728→
   729→  // Invoice title + order number
   730→  addText('فاتورة ضريبية مبسطة', 'center', Math.round(FS * 1.05), true);
   731→  addGap(Math.round(FS * 0.8));
   732→
   733→  const orderNumFmt = String(opts.orderNumber).replace(/\D/g, '').padStart(4, '0') || opts.orderNumber;
   734→  addText(`#${orderNumFmt}`, 'center', Math.round(FS * 2.4), true);
   735→  addGap(Math.round(FS * 0.4));
   736→
   737→  // Info block — no separator lines
   738→  addRow('التاريخ:', opts.orderDate, Math.round(FS * 0.88));
   739→  addRow('الكاشير:', opts.cashierName, Math.round(FS * 0.88));
   740→  if (opts.customerName && opts.customerName !== 'عميل نقدي') addRow('العميل:', opts.customerName, Math.round(FS * 0.88));
   741→  if (opts.tableNumber) addRow('الطاولة:', opts.tableNumber, Math.round(FS * 0.88));
   742→  if (opts.orderType)   addRow('نوع الطلب:', opts.orderType, Math.round(FS * 0.88));
   743→  addGap(6);
   744→
   745→  // Items — no separator lines, small gap between items
   746→  for (const item of opts.items) {
   747→    addText(item.name, 'right', Math.round(FS * 0.95), true);
   748→    if (item.nameEn && item.nameEn.trim() && item.nameEn !== item.name) {
   749→      addText(item.nameEn, 'right', Math.round(FS * 0.78), false, '#555');
   750→    }
   751→    addRow(`${item.qty} × ${item.price.toFixed(2)} ر.س`, `${(item.qty * item.price).toFixed(2)} ر.س`, Math.round(FS * 0.85));
   752→    if (item.addons?.length) {
   753→      for (const a of item.addons) addText(`+ ${a}`, 'right', Math.round(FS * 0.78), false, '#555');
   754→    }
   755→    addGap(5);
   756→  }
   757→
   758→  addGap(4);
   759→
   760→  // Totals — no separator lines
   761→  addRow('قبل الضريبة:', `${opts.subtotal.toFixed(2)} ر.س`, Math.round(FS * 0.88));
   762→  addRow('ضريبة القيمة المضافة 15%:', `${opts.vat.toFixed(2)} ر.س`, Math.round(FS * 0.88));
   763→  if (opts.discount && opts.discount > 0)
   764→    addRow('الخصم:', `-${opts.discount.toFixed(2)} ر.س`, Math.round(FS * 0.88), false, false, '#16a34a');
   765→  addRow('الإجمالي:', `${opts.total.toFixed(2)} ر.س`, Math.round(FS * 1.05), false, true);
   766→  addGap(4);
   767→
   768→  // Payment — no separator
   769→  const _receiptPayLabel = (() => {
   770→    const m = (opts.paymentMethod || '').toLowerCase();
   771→    if (m === 'cash') return 'نقدي';
   772→    if (m === 'card' || m === 'network' || m === 'pos' || m === 'pos-network') return 'شبكة';
   773→    if (m === 'apple_pay' || m === 'neoleap-apple-pay' || m === 'paymob-apple-pay') return 'Apple Pay';
   774→    if (m === 'geidea' || m === 'paymob' || m === 'paymob-card') return 'بطاقة ائتمان';
   775→    if (m === 'mada' || m === 'bank_transfer') return 'تحويل بنكي';
   776→    if (m === 'rajhi') return 'بنك الراجحي';
   777→    if (m === 'alinma') return 'Alinma Pay';
   778→    if (m === 'split') return 'نقدي + شبكة';
   779→    if (m === 'loyalty' || m === 'qahwa-card' || m === 'qirox-card') return 'بطاقة ولاء';
   780→    return opts.paymentMethod;
   781→  })();
   782→  addRow('طريقة الدفع:', _receiptPayLabel, Math.round(FS * 0.88));
   783→  if (opts.splitPayment) {
   784→    if (opts.splitPayment.cash > 0) addRow('  💵 نقدي:', `${opts.splitPayment.cash.toFixed(2)} ر.س`, Math.round(FS * 0.82));
   785→    if (opts.splitPayment.card > 0) addRow('  💳 شبكة:', `${opts.splitPayment.card.toFixed(2)} ر.س`, Math.round(FS * 0.82));
   786→  }
   787→  if ((opts as any).cashReceived && (opts as any).cashReceived > 0 && !opts.splitPayment) {
   788→    const cr = (opts as any).cashReceived as number;
   789→    addRow('  المستلم:', `${cr.toFixed(2)} ر.س`, Math.round(FS * 0.82));
   790→    addRow('  الباقي:', `${Math.max(0, cr - opts.total).toFixed(2)} ر.س`, Math.round(FS * 0.82), false, false, '#16a34a');
   791→  }
   792→
   793→  // ── QR codes: tracking then ZATCA, one below the other, no line between ──
   794→  addGap(10);
   795→  if (trackImg && trackImg.naturalWidth > 0) {
   796→    addImg(trackImg, Math.round(DW * 0.50));
   797→    addGap(6);
   798→    addText('امسح للتتبع وتسجيل النقاط', 'center', Math.round(FS * 0.8), true, '#333');
   799→    addGap(Math.round(FS * 1.2));
   800→  }
   801→  if (zatcaImg && zatcaImg.naturalWidth > 0) {
   802→    addGap(6);
   803→    addImg(zatcaImg, Math.round(DW * 0.28));
   804→    addGap(6);
   805→    addText('ZATCA · باركود الضريبة', 'center', Math.round(FS * 0.72), false, '#555');
   806→    addGap(Math.round(FS * 1.2));
   807→  }
   808→
   809→  // ── ONE separator line before footer ────────────────────────────────────
   810→  addLine(true);
   811→
   812→  // Footer
   813→  addText('** شكراً لزيارتكم **', 'center', Math.round(FS * 1.0), true);
   814→  addText('الأسعار شاملة ضريبة القيمة المضافة 15%', 'center', Math.round(FS * 0.78), false, '#444');
   815→
   816→  addGap(opts.feedLines ? opts.feedLines * 8 : 24);
   817→
   818→  // ── Render to canvas ─────────────────────────────────────────────────────
   819→  const canvas = document.createElement('canvas');
   820→  canvas.width = DW;
   821→  canvas.height = 5000;  // will be trimmed
   822→  const ctx = canvas.getContext('2d')!;
   823→  ctx.fillStyle = '#fff';
   824→  ctx.fillRect(0, 0, DW, 5000);
   825→
   826→  let y = 0;
   827→
   828→  const measureTextH = (fs: number) => Math.ceil(fs * 1.45);
   829→
   830→  for (const op of ops) {
   831→    if (op.type === 'gap') {
   832→      y += op.h;
   833→    } else if (op.type === 'line') {
   834→      ctx.strokeStyle = '#000';
   835→      ctx.lineWidth = op.thick ? 2.5 : 1;
   836→      ctx.setLineDash(op.dashed ? [6, 5] : []);
   837→      ctx.beginPath();
   838→      ctx.moveTo(PAD, y + 4);
   839→      ctx.lineTo(DW - PAD, y + 4);
   840→      ctx.stroke();
   841→      ctx.setLineDash([]);
   842→      y += 10;
   843→    } else if (op.type === 'text') {
   844→      const lh = measureTextH(op.fs);
   845→      ctx.font = `${op.bold ? '700' : '400'} ${op.fs}px Tahoma, Arial, sans-serif`;
   846→      ctx.fillStyle = op.color || '#000';
   847→      ctx.direction = 'rtl';
   848→      if (op.align === 'center') {
   849→        ctx.textAlign = 'center';
   850→        ctx.fillText(op.text, DW / 2, y);
   851→      } else if (op.align === 'right') {
   852→        ctx.textAlign = 'right';
   853→        ctx.fillText(op.text, DW - PAD, y);
   854→      } else {
   855→        ctx.textAlign = 'left';
   856→        ctx.fillText(op.text, PAD, y);
   857→      }
   858→      y += lh;
   859→    } else if (op.type === 'row') {
   860→      const lh = measureTextH(op.fs);
   861→      // Label (right side)
   862→      ctx.font = `${op.boldLabel ? '700' : '400'} ${op.fs}px Tahoma, Arial, sans-serif`;
   863→      ctx.fillStyle = op.color || '#000';
   864→      ctx.direction = 'rtl';
   865→      ctx.textAlign = 'right';
   866→      ctx.fillText(op.label, DW - PAD, y);
   867→      // Value (left side)
   868→      ctx.font = `${op.boldValue ? '700' : '400'} ${op.fs}px Tahoma, Arial, sans-serif`;
   869→      ctx.textAlign = 'left';
   870→      ctx.direction = 'ltr';
   871→      ctx.fillText(op.value, PAD, y);
   872→      y += lh;
   873→    } else if (op.type === 'img') {
   874→      const size = Math.min(op.size, CONTENT_W);
   875→      const x = Math.floor((DW - size) / 2);
   876→      ctx.drawImage(op.img, x, y, size, size);
   877→      y += size + 4;
   878→    }
   879→  }
   880→
   881→  // Trim canvas to actual content height
   882→  const finalH = Math.min(y + 10, 5000);
   883→  const trimmed = document.createElement('canvas');
   884→  trimmed.width = DW;
   885→  trimmed.height = finalH;
   886→  const tctx = trimmed.getContext('2d')!;
   887→  tctx.drawImage(canvas, 0, 0);
   888→  return trimmed;
   889→}
   890→
   891→/**
   892→ * Builds the receipt as a Canvas 2D bitmap, then converts to ESC/POS GS v 0 raster bytes
   893→ * for direct thermal printer transmission. Arabic-safe — uses native browser text shaping.
   894→ */
   895→export async function buildReceiptBitmapEscPos(opts: ReceiptBitmapOpts): Promise<Uint8Array> {
   896→  const canvas = await buildReceiptCanvas(opts);
   897→  const DW = canvas.width;
   898→  const finalH = canvas.height;
   899→  const ctx = canvas.getContext('2d')!;
   900→
   901→  // ── Convert to ESC/POS GS v 0 raster bytes ───────────────────────────────
   902→  const imgData = ctx.getImageData(0, 0, DW, finalH);
   903→  const bpl = Math.ceil(DW / 8);
   904→  const raster: number[] = [];
   905→
   906→  // Init + GS v 0 header
   907→  raster.push(0x1b, 0x40);  // ESC @ init
   908→  raster.push(0x1d, 0x76, 0x30, 0x00);
   909→  raster.push(bpl & 0xff, (bpl >> 8) & 0xff);
   910→  raster.push(finalH & 0xff, (finalH >> 8) & 0xff);
   911→
   912→  for (let row = 0; row < finalH; row++) {
   913→    for (let bx = 0; bx < bpl; bx++) {
   914→      let byte = 0;
   915→      for (let bit = 0; bit < 8; bit++) {
   916→        const px = bx * 8 + bit;
   917→        if (px < DW) {
   918→          const i = (row * DW + px) * 4;
   919→          const lum = 0.299 * imgData.data[i] + 0.587 * imgData.data[i + 1] + 0.114 * imgData.data[i + 2];
   920→          if (lum < 128) byte |= 1 << (7 - bit);
   921→        }
   922→      }
   923→      raster.push(byte);
   924→    }
   925→  }
   926→
   927→  // Feed + full cut
   928→  raster.push(0x1b, 0x64, 4);    // ESC d 4 — feed 4 lines
   929→  raster.push(0x1d, 0x56, 0x41, 0x03);  // GS V A 3 — full cut
   930→
   931→  return new Uint8Array(raster);
   932→}
   933→
   934→/**
   935→ * Converts a receipt PNG data URL (from renderReceiptPreviewToPng) to ESC/POS raster bytes.
   936→ * This ensures the thermal printer output is PIXEL-PERFECT identical to the on-screen preview.
   937→ * The image is scaled to fit the paper dot width while preserving the full receipt height.
   938→ */
   939→export async function receiptPngToEscPos(
   940→  dataUrl: string,
   941→  paperWidth: '58mm' | '80mm' = '80mm',
   942→  feedLines: number = 4,
   943→): Promise<Uint8Array> {
   944→  const dotWidth = paperWidth === '58mm' ? 384 : 576;
   945→
   946→  // Load the PNG image
   947→  const img = new Image();
   948→  img.src = dataUrl;
   949→  await new Promise<void>(res => {
   950→    if (img.complete && img.naturalWidth > 0) { res(); return; }
   951→    img.onload = () => res();
   952→    img.onerror = () => res();
   953→    setTimeout(res, 5000);
   954→  });
   955→
   956→  if (!img.naturalWidth || !img.naturalHeight) {
   957→    throw new Error('[receiptPngToEscPos] Failed to load receipt PNG image');
   958→  }
   959→
   960→  // Scale image to fill exactly dotWidth pixels, preserve aspect ratio for height
   961→  const scale = dotWidth / img.naturalWidth;
   962→  const scaledH = Math.ceil(img.naturalHeight * scale);
   963→
   964→  const canvas = document.createElement('canvas');
   965→  canvas.width = dotWidth;
   966→  canvas.height = scaledH;
   967→  const ctx = canvas.getContext('2d')!;
   968→  ctx.fillStyle = '#ffffff';
   969→  ctx.fillRect(0, 0, dotWidth, scaledH);
   970→  ctx.drawImage(img, 0, 0, dotWidth, scaledH);
   971→
   972→  const imgData = ctx.getImageData(0, 0, dotWidth, scaledH);
   973→  const bpl = Math.ceil(dotWidth / 8);
   974→
   975→  const raster: number[] = [];
   976→  // ESC @ — initialize printer
   977→  raster.push(0x1b, 0x40);
   978→  // GS v 0 — raster image header
   979→  raster.push(0x1d, 0x76, 0x30, 0x00);
   980→  raster.push(bpl & 0xff, (bpl >> 8) & 0xff);
   981→  raster.push(scaledH & 0xff, (scaledH >> 8) & 0xff);
   982→
   983→  for (let row = 0; row < scaledH; row++) {
   984→    for (let bx = 0; bx < bpl; bx++) {
   985→      let byte = 0;
   986→      for (let bit = 0; bit < 8; bit++) {
   987→        const px = bx * 8 + bit;
   988→        if (px < dotWidth) {
   989→          const i = (row * dotWidth + px) * 4;
   990→          const lum = 0.299 * imgData.data[i] + 0.587 * imgData.data[i + 1] + 0.114 * imgData.data[i + 2];
   991→          if (lum < 128) byte |= 1 << (7 - bit);
   992→        }
   993→      }
   994→      raster.push(byte);
   995→    }
   996→  }
   997→
   998→  // Feed + full cut
   999→  raster.push(0x1b, 0x64, Math.max(0, feedLines));
  1000→  raster.push(0x1d, 0x56, 0x41, 0x03);
  1001→
  1002→  return new Uint8Array(raster);
  1003→}
  1004→
  1005→/**
  1006→ * Renders a compact "Employee Copy" / kitchen ticket as a Canvas 2D bitmap.
  1007→ * Same Arabic-safe pipeline as the main receipt — no HTML, no encoding issues.
  1008→ */
  1009→export interface EmployeeCopyOpts {
  1010→  orderNumber: string;
  1011→  tableNumber?: string;
  1012→  orderType?: string;
  1013→  cashierName: string;
  1014→  items: Array<{ name: string; nameEn?: string; qty: number; addons?: string[] }>;
  1015→  notes?: string;
  1016→  total?: number;
  1017→  orderDate?: string;
  1018→  paperWidth: '58mm' | '80mm';
  1019→}
  1020→
  1021→export async function buildEmployeeCopyCanvas(opts: EmployeeCopyOpts): Promise<HTMLCanvasElement> {
  1022→  const DW = opts.paperWidth === '58mm' ? 384 : 576;
  1023→  const PAD = Math.round(DW * 0.04);
  1024→  const FS = opts.paperWidth === '58mm' ? 20 : 26;
  1025→
  1026→  const canvas = document.createElement('canvas');
  1027→  canvas.width = DW;
  1028→  canvas.height = 4000;
  1029→  const ctx = canvas.getContext('2d')!;
  1030→  ctx.fillStyle = '#fff';
  1031→  ctx.fillRect(0, 0, DW, 4000);
  1032→
  1033→  const lh = (fs: number) => Math.ceil(fs * 1.6);
  1034→  // 2 blank lines at the very start of every kitchen invoice
  1035→  let y = Math.round(lh(FS) * 2);
  1036→
  1037→  const drawCenter = (text: string, fs: number, bold = false) => {
  1038→    ctx.font = `${bold ? '700' : '400'} ${fs}px Tahoma, Arial, sans-serif`;
  1039→    ctx.fillStyle = '#000';
  1040→    ctx.direction = 'rtl';
  1041→    ctx.textAlign = 'center';
  1042→    ctx.fillText(text, DW / 2, y);
  1043→    y += lh(fs);
  1044→  };
  1045→  const drawRight = (text: string, fs: number, bold = false, color = '#000') => {
  1046→    ctx.font = `${bold ? '700' : '400'} ${fs}px Tahoma, Arial, sans-serif`;
  1047→    ctx.fillStyle = color;
  1048→    ctx.direction = 'rtl';
  1049→    ctx.textAlign = 'right';
  1050→    ctx.fillText(text, DW - PAD, y);
  1051→    y += lh(fs);
  1052→  };
  1053→  // 2 blank lines above + line + 2 blank lines below
  1054→  const LINE_GAP_K = Math.round(lh(FS) * 2);
  1055→  const drawLine = (thick = false, dashed = false) => {
  1056→    y += LINE_GAP_K;
  1057→    ctx.strokeStyle = '#000';
  1058→    ctx.lineWidth = thick ? 2.5 : 1;
  1059→    ctx.setLineDash(dashed ? [6, 5] : []);
  1060→    ctx.beginPath();
  1061→    ctx.moveTo(PAD, y);
  1062→    ctx.lineTo(DW - PAD, y);
  1063→    ctx.stroke();
  1064→    ctx.setLineDash([]);
  1065→    y += LINE_GAP_K;
  1066→  };
  1067→
  1068→  // ── HEADER: نسخة الموظف ──
  1069→  drawCenter('نسخة الموظف', Math.round(FS * 1.2), true);
  1070→
  1071→  // ── Order number (large) ──
  1072→  const orderFmt = `#${String(opts.orderNumber).replace(/\D/g, '').padStart(4, '0') || opts.orderNumber}`;
  1073→  drawCenter(orderFmt, Math.round(FS * 2.2), true);
  1074→  y += 6;
  1075→
  1076→  // ── Info rows — no lines ──
  1077→  if (opts.cashierName) drawRight(`الكاشير: ${opts.cashierName}`, Math.round(FS * 0.9));
  1078→  if (opts.orderType)   drawRight(`نوع الطلب: ${opts.orderType}`, Math.round(FS * 0.9));
  1079→  if (opts.tableNumber) drawRight(`الطاولة: ${opts.tableNumber}`, Math.round(FS * 0.9));
  1080→  if (opts.orderDate)   drawRight(`الوقت: ${opts.orderDate}`, Math.round(FS * 0.85));
  1081→  y += 6;
  1082→
  1083→  // ── Items: no separator lines ──
  1084→  for (const item of opts.items) {
  1085→    drawRight(`${item.qty} × ${item.name}`, Math.round(FS * 1.1), true);
  1086→    if (item.nameEn && item.nameEn.trim() && item.nameEn !== item.name) {
  1087→      ctx.font = `400 ${Math.round(FS * 0.85)}px Tahoma, Arial, sans-serif`;
  1088→      ctx.fillStyle = '#666';
  1089→      ctx.direction = 'ltr';
  1090→      ctx.textAlign = 'left';
  1091→      ctx.fillText(item.nameEn, PAD, y);
  1092→      y += lh(Math.round(FS * 0.85));
  1093→    }
  1094→    if (item.addons?.length) {
  1095→      for (const a of item.addons) {
  1096→        drawRight(`+ ${a}`, Math.round(FS * 0.9), false, '#555');
  1097→      }
  1098→    }
  1099→    y += 4;
  1100→  }
  1101→
  1102→  if (opts.notes) {
  1103→    y += 4;
  1104→    drawRight(`ملاحظات: ${opts.notes}`, Math.round(FS * 0.95), false, '#222');
  1105→  }
  1106→
  1107→  y += 32; // feed
  1108→
  1109→  // Trim
  1110→  const finalH = Math.min(y + 10, 4000);
  1111→  const trimmed = document.createElement('canvas');
  1112→  trimmed.width = DW;
  1113→  trimmed.height = finalH;
