  1425→    buf.push(...CMD.BOLD_ON);
  1426→    buf.push(...line('*** ملاحظات ***'));
  1427→    buf.push(...CMD.BOLD_OFF);
  1428→    buf.push(...line(data.notes));
  1429→  }
  1430→
  1431→  // ── Footer ─────────────────────────────────────────────────────────────────
  1432→  buf.push(0x0a, ...dottedLine(w), 0x0a);
