  1443→// ─── Image-based receipt builder ─────────────────────────────────────────────
  1444→// Renders HTML to a canvas then encodes as ESC/POS raster image.
  1445→// This is the most reliable approach for Arabic text — no encoding issues at all.
  1446→// Works with any thermal printer regardless of installed code pages.
  1447→
  1448→export async function buildEscPosImageReceipt(
  1449→  html: string,
  1450→  paperWidth: '58mm' | '80mm',
  1451→  feedLines: number = 4,
  1452→): Promise<Uint8Array> {
  1453→  // Printer dot widths at 203 dpi: 58mm → 384 dots, 80mm → 576 dots
  1454→  const dotWidth = paperWidth === '58mm' ? 384 : 576;
  1455→
  1456→  // Strip Google Fonts @import — use only system Arabic fonts (Tahoma/Arial)
  1457→  // so rendering works even without internet access
  1458→  let safeHtml = html
  1459→    .replace(/@import\s+url\([^)]*fonts\.googleapis[^)]*\)[^;]*;/gi, '')
  1460→    .replace(/font-family\s*:\s*['"]?Cairo['"]?\s*,?/gi, 'font-family: Tahoma, Arial,');
  1461→
  1462→  // Use position:absolute (NOT fixed) — fixed breaks scrollHeight/offsetHeight calculation
  1463→  // Place far off-screen horizontally but at top:0 so the full height is measurable
  1464→  const wrapper = document.createElement('div');
  1465→  wrapper.style.cssText = [
  1466→    `width:${dotWidth}px`,
  1467→    'position:absolute',
  1468→    'left:-99999px',
  1469→    'top:0',
  1470→    'background:#fff',
  1471→    'color:#000',
  1472→    'visibility:visible',
  1473→    'pointer-events:none',
  1474→    'overflow:visible',
  1475→  ].join(';');
  1476→
  1477→  // Insert a scoped <style> block that resets page width
  1478→  const scopeStyle = `<style>
  1479→    html,body{margin:0;padding:0;background:#fff;color:#000;}
  1480→    *{box-sizing:border-box;}
  1481→  </style>`;
  1482→  wrapper.innerHTML = scopeStyle + safeHtml;
  1483→  document.body.appendChild(wrapper);
  1484→
  1485→  // Wait for ALL images to finish loading before measuring or capturing
  1486→  const images = Array.from(wrapper.querySelectorAll('img'));
  1487→  await Promise.all(images.map(img => {
  1488→    if (img.complete && img.naturalWidth > 0) return Promise.resolve();
  1489→    return new Promise<void>(res => {
  1490→      const done = () => res();
  1491→      img.addEventListener('load', done, { once: true });
  1492→      img.addEventListener('error', done, { once: true });
  1493→      setTimeout(done, 4000); // safety timeout per image
  1494→    });
  1495→  }));
  1496→
  1497→  // Brief extra delay to let flexbox / layout settle after images load
  1498→  await new Promise(r => setTimeout(r, 200));
  1499→
  1500→  // Measure full rendered height — offsetHeight works correctly for absolute elements
  1501→  const contentHeight = Math.max(wrapper.offsetHeight, wrapper.scrollHeight, 300);
  1502→
  1503→  let canvas: HTMLCanvasElement;
  1504→  try {
  1505→    const { default: html2canvas } = await import('html2canvas');
  1506→    canvas = await html2canvas(wrapper, {
  1507→      width: dotWidth,
  1508→      height: contentHeight,
  1509→      scale: 1,
  1510→      backgroundColor: '#ffffff',
  1511→      useCORS: false,
  1512→      logging: false,
  1513→      allowTaint: true,
  1514→      imageTimeout: 5000,
  1515→      removeContainer: false,
  1516→      // Ensure background colors (black boxes etc.) are captured
  1517→      onclone: (_doc: Document, el: HTMLElement) => {
  1518→        el.style.overflow = 'visible';
  1519→      },
  1520→    });
  1521→  } finally {
  1522→    wrapper.remove();
  1523→  }
  1524→
  1525→  const ctx = canvas.getContext('2d');
  1526→  if (!ctx) throw new Error('Canvas 2D context unavailable');
  1527→
  1528→  const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
  1529→  const { width, height } = canvas;
  1530→  const actualBpl = Math.ceil(width / 8);
  1531→
  1532→  // Build ESC/POS bytes ───────────────────────────────────────────────────────
  1533→  const buf: number[] = [];
  1534→
  1535→  // Init printer
  1536→  buf.push(ESC, 0x40);
  1537→
  1538→  // GS v 0 — Raster bit image (most compatible across Xprinter / Epson clones)
  1539→  // Format: GS v 0 m xL xH yL yH d...
  1540→  // m = 0 (normal), xL/xH = bytes per line, yL/yH = number of dot rows
  1541→  buf.push(GS, 0x76, 0x30, 0x00);
  1542→  buf.push(actualBpl & 0xff, (actualBpl >> 8) & 0xff);
  1543→  buf.push(height & 0xff, (height >> 8) & 0xff);
  1544→
  1545→  // Rasterize: luminance threshold 128 (dark pixel → bit=1, MSB first)
  1546→  for (let y = 0; y < height; y++) {
  1547→    for (let bx = 0; bx < actualBpl; bx++) {
  1548→      let byte = 0;
  1549→      for (let bit = 0; bit < 8; bit++) {
  1550→        const px = bx * 8 + bit;
  1551→        if (px < width) {
  1552→          const i = (y * width + px) * 4;
  1553→          const lum = 0.299 * imgData.data[i] + 0.587 * imgData.data[i + 1] + 0.114 * imgData.data[i + 2];
  1554→          if (lum < 128) byte |= 1 << (7 - bit);
  1555→        }
  1556→      }
  1557→      buf.push(byte);
  1558→    }
  1559→  }
  1560→
  1561→  // Feed lines then full cut
  1562→  buf.push(ESC, 0x64, Math.max(1, feedLines));
  1563→  buf.push(GS, 0x56, 0x41, 0x03);
  1564→
  1565→  return new Uint8Array(buf);
  1566→}
