  1586→let _qzLoadPromise: Promise<any> | null = null;
  1587→let _qzConnected = false;
  1588→
  1589→async function _loadQZScript(): Promise<any> {
  1590→  if ((window as any).qz) return (window as any).qz;
  1591→  if (_qzLoadPromise) return _qzLoadPromise;
  1592→
  1593→  _qzLoadPromise = new Promise<any>((resolve, reject) => {
  1594→    if (document.querySelector('script[data-qz-tray]')) {
  1595→      const poll = setInterval(() => {
  1596→        if ((window as any).qz) { clearInterval(poll); resolve((window as any).qz); }
  1597→      }, 100);
  1598→      setTimeout(() => { clearInterval(poll); reject(new Error('QZ timeout')); }, 10000);
  1599→      return;
  1600→    }
